use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicU32, AtomicUsize, Ordering};
use std::sync::{Arc, Mutex};
use std::thread;

thread_local! {
    static IN_POOL: std::cell::Cell<bool> = const { std::cell::Cell::new(false) };
}

pub fn is_in_pool() -> bool {
    IN_POOL.with(|p| p.get())
}

pub fn set_in_pool(v: bool) {
    IN_POOL.with(|p| p.set(v));
}

pub struct GlobalPool {
    signal: Arc<JobSignal>,
    pub k: usize,
}

/// Lock-free dispatch path.
///
/// Workers spin on `generation` (short window) then park. Main dispatches
/// by writing `job`, setting `active_count`, bumping `generation`, then
/// unparking all worker handles in case any parked. This replaces the
/// prior `Mutex<JobState>` + `Condvar::notify_all()` dispatch, which cost
/// ~5-10 µs on macOS (the notify_all wakes K-1 workers serially). Atomic
/// dispatch is ~200 ns — the single largest per-call perf lever for
/// sub-millisecond workloads.
struct JobSignal {
    job: UnsafeCell<Option<JobData>>,
    generation: AtomicUsize,
    active_generation: AtomicUsize,
    active_count: AtomicUsize,
    worker_threads: Mutex<Vec<thread::Thread>>,
}

// SAFETY: `job` is only mutated by the main thread, and only while it holds
// the outer `POOL` mutex (so only one writer at a time). Workers observe the
// write after acquire-loading `generation`, which synchronizes-with the
// release-store on dispatch.
unsafe impl Sync for JobSignal {}

#[derive(Clone)]
struct JobData {
    generation: usize,
    dispatch_count: usize,
    func: *mut (),
    invoke: unsafe fn(*mut (), usize),
}

unsafe impl Send for JobData {}
unsafe impl Sync for JobData {}

static POOL: std::sync::OnceLock<Mutex<GlobalPool>> = std::sync::OnceLock::new();

pub fn get_pool() -> Option<std::sync::MutexGuard<'static, GlobalPool>> {
    let pool_mutex = POOL.get_or_init(|| {
        let k = std::env::var("GNOSIS_NUM_THREADS")
            .or_else(|_| std::env::var("RAYON_NUM_THREADS"))
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or_else(|| {
                std::thread::available_parallelism()
                    .map(|n| n.get())
                    .unwrap_or(1)
            });
        let signal = Arc::new(JobSignal {
            job: UnsafeCell::new(None),
            generation: AtomicUsize::new(0),
            active_generation: AtomicUsize::new(0),
            active_count: AtomicUsize::new(0),
            worker_threads: Mutex::new(Vec::with_capacity(k - 1)),
        });

        for i in 1..k {
            let sig = signal.clone();
            let handle = thread::Builder::new()
                .name(format!("frf-worker-{}", i))
                .spawn(move || worker_loop(sig, i))
                .expect("failed to spawn FRF worker");
            signal
                .worker_threads
                .lock()
                .unwrap()
                .push(handle.thread().clone());
        }

        Mutex::new(GlobalPool { signal, k })
    });
    pool_mutex.try_lock().ok()
}

/// Worker spin budget before falling back to `park()`.
///
/// Exposed as an `AtomicU32` (not a `const`) specifically so a follow-on
/// PR can make it self-regulating per Taylor's C0/C1/C2 framing from
/// FORMAL_LEDGER.md §Triad: C0 is the invariant inter-dispatch cadence
/// (unknown a priori), C1 is the observed park vs spin-win signal, C2
/// is the budget adjustment. An initial AIMD experiment against C1 was
/// unstable (tuning found local minima that regressed real workloads by
/// >20x), so the current build ships a fixed value.
///
/// The principled replacement is target-rate EWMA (aim for ~10 % park-hit rate)
/// or a full metacognitive chain tracking inter-dispatch gap distribution.
///
/// 65_536 hints ≈ 20 µs on aarch64 at ~3.2 GHz -- long enough to cover
/// the gap between successive par_iter calls in sustained-load loops so
/// workers stay hot, short enough that idle pools don't burn noticeable
/// power.
static WORKER_SPIN_LIMIT: AtomicU32 = AtomicU32::new(65_536);

const WORKER_SPIN_MIN: u32 = 256;
const WORKER_SPIN_MAX: u32 = 1_048_576; // ~300 µs ceiling

fn worker_loop(signal: Arc<JobSignal>, index: usize) {
    let mut last_gen = 0;
    loop {
        // Wait for a new generation. Spin first (tight submit-path hot
        // loop), then park. Track whether we had to park so we can AIMD-
        // tune the global spin budget.
        let budget = WORKER_SPIN_LIMIT.load(Ordering::Relaxed);
        let mut spins = 0u32;
        let mut parked = false;
        loop {
            let current = signal.generation.load(Ordering::Acquire);
            if current != last_gen {
                last_gen = current;
                break;
            }
            if spins < budget {
                std::hint::spin_loop();
                spins += 1;
            } else {
                parked = true;
                std::thread::park();
            }
        }

        // C1 signal → C2 integration. Balanced AIMD: grow +6.25% on park,
        // shrink -6.25% on quick spin-win (< ¼ budget), hold otherwise.
        if index == 1 {
            if parked {
                let new = budget.saturating_add(budget / 16).min(WORKER_SPIN_MAX);
                WORKER_SPIN_LIMIT.store(new, Ordering::Relaxed);
            } else if spins < budget / 4 {
                let new = budget.saturating_sub(budget / 16).max(WORKER_SPIN_MIN);
                WORKER_SPIN_LIMIT.store(new, Ordering::Relaxed);
            }
        }

        // Read job. Safe because: (1) only main writes, (2) writes happen
        // before the generation release-store, (3) we just did an acquire
        // load of generation, so the write is visible.
        let job = unsafe {
            (*signal.job.get())
                .as_ref()
                .expect("dispatched generation with no job")
                .clone()
        };

        // Small-N fast path: a worker that was not selected for generation N
        // may still be spinning while the main thread advances the job slot to
        // generation N+1. The payload generation keeps that late observer from
        // invoking the next job under the old generation.
        if job.generation != last_gen || index >= job.dispatch_count {
            continue;
        }

        unsafe {
            set_in_pool(true);
            (job.invoke)(job.func, index);
            set_in_pool(false);
        }

        if signal.active_generation.load(Ordering::Acquire) == job.generation {
            signal.active_count.fetch_sub(1, Ordering::Release);
        }
    }
}

pub fn execute_with_pool<F>(pool: &GlobalPool, f: &F)
where
    F: Fn(usize) + Send + Sync,
{
    execute_with_pool_k_eff(pool, pool.k, f)
}

/// Dispatch a job to only the first `k_eff` worker slots (main + helpers).
///
/// `k_eff` MUST be `1..=pool.k`. When `k_eff < pool.k`, helper indices in
/// `k_eff..pool.k` stay parked: we never unpark them, and we don't include
/// them in `active_count`. If one of those helpers happens to be spinning
/// when the generation bumps it observes the bump but skips the job (the
/// `dispatch_count` check in `worker_loop`).
///
/// Approach (A) small-N fast path: callers compute `k_eff` from the
/// problem size to avoid paying the wake-up cost of K-1 helpers when each
/// would see only a couple of items. The L=16 / L=32 stride-24 regression
/// is exactly this regime.
pub fn execute_with_pool_k_eff<F>(pool: &GlobalPool, k_eff: usize, f: &F)
where
    F: Fn(usize) + Send + Sync,
{
    if pool.k <= 1 || k_eff <= 1 {
        f(0);
        return;
    }

    unsafe fn invoke_f<F: Fn(usize)>(ptr: *mut (), index: usize) {
        let f = unsafe { &*(ptr as *const F) };
        f(index);
    }

    let k_eff = std::cmp::min(k_eff, pool.k);

    // Lock-free dispatch:
    //   1. Write the job (safe: outer POOL mutex serializes writers)
    //   2. Set active_count (workers will decrement)
    //   3. Release-bump generation (publishes job + counters)
    //   4. Unpark only the helpers we actually selected
    let generation = pool
        .signal
        .generation
        .load(Ordering::Relaxed)
        .wrapping_add(1);
    unsafe {
        *pool.signal.job.get() = Some(JobData {
            generation,
            dispatch_count: k_eff,
            func: f as *const _ as *mut (),
            invoke: invoke_f::<F>,
        });
    }
    pool.signal
        .active_generation
        .store(generation, Ordering::Release);
    pool.signal.active_count.store(k_eff - 1, Ordering::Release);
    pool.signal.generation.store(generation, Ordering::Release);
    {
        let helpers_to_wake = k_eff - 1;
        let workers: Vec<thread::Thread> = {
            let workers_lock = pool.signal.worker_threads.lock().unwrap();
            workers_lock.iter().take(helpers_to_wake).cloned().collect()
        };
        for w in workers {
            w.unpark();
        }
    }

    set_in_pool(true);
    f(0);
    set_in_pool(false);

    while pool.signal.active_count.load(Ordering::Acquire) > 0 {
        std::hint::spin_loop();
    }
}

#[cfg(test)]
mod tests {
    use super::{execute_with_pool_k_eff, get_pool};
    use std::sync::atomic::{AtomicUsize, Ordering};

    #[test]
    fn small_k_eff_generations_do_not_double_invoke_later_jobs() {
        let Some(pool) = get_pool() else {
            return;
        };
        if pool.k < 3 {
            return;
        }

        for iteration in 0..10_000 {
            let k_eff = if iteration % 2 == 0 { 2 } else { pool.k };
            let counts = (0..k_eff).map(|_| AtomicUsize::new(0)).collect::<Vec<_>>();

            execute_with_pool_k_eff(&pool, k_eff, &|index| {
                assert!(index < k_eff);
                counts[index].fetch_add(1, Ordering::SeqCst);
                for _ in 0..64 {
                    std::hint::spin_loop();
                }
            });

            for count in counts {
                assert_eq!(count.load(Ordering::SeqCst), 1);
            }
        }
    }
}
